"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useAccount, useReadContract } from "wagmi";
import { CDSCard } from "@/components/CDSCard";
import { PriceFeed } from "@/components/PriceFeed";
import { CDS_ABI } from "@/lib/abis";
import DEPLOYMENTS from "@/lib/deployments.json";

interface CDSData {
  id: number;
  buyer: string;
  seller: string;
  triggerPrice: bigint;
  maturityTimestamp: bigint;
  status: number;
  notionalDeposited: boolean;
  notionalHandle: string;
}

function SkeletonCard() {
  return (
    <div className="bg-gray-900 border border-gray-800 rounded-xl p-5 animate-pulse">
      <div className="flex justify-between mb-4">
        <div className="space-y-2">
          <div className="h-3 w-20 bg-gray-800 rounded" />
          <div className="h-4 w-16 bg-gray-800 rounded" />
        </div>
        <div className="space-y-2 text-right">
          <div className="h-3 w-20 bg-gray-800 rounded ml-auto" />
          <div className="h-6 w-24 bg-gray-800 rounded ml-auto" />
        </div>
      </div>
      <div className="grid grid-cols-2 gap-3">
        <div className="h-12 bg-gray-800 rounded" />
        <div className="h-12 bg-gray-800 rounded" />
        <div className="h-12 bg-gray-800 rounded" />
        <div className="h-12 bg-gray-800 rounded" />
      </div>
    </div>
  );
}

export default function Home() {
  const { address } = useAccount();
  const [contracts, setContracts] = useState<CDSData[]>([]);
  const [loading, setLoading] = useState(true);

  const cdsAddress = DEPLOYMENTS.ConfidentialCDS
    ? (DEPLOYMENTS.ConfidentialCDS as `0x${string}`)
    : undefined;

  const { data: total } = useReadContract({
    address: cdsAddress,
    abi: CDS_ABI,
    functionName: "totalContracts",
    query: { enabled: !!cdsAddress },
  });

  useEffect(() => {
    async function loadContracts() {
      if (!total || !cdsAddress) {
        setLoading(false);
        return;
      }
      const { createPublicClient, http } = await import("viem");
      const { arbitrumSepolia } = await import("viem/chains");
      const client = createPublicClient({
        chain: arbitrumSepolia,
        transport: http("https://sepolia-rollup.arbitrum.io/rpc"),
      });

      const count = Number(total);
      const results: CDSData[] = [];

      for (let i = 0; i < count; i++) {
        try {
          const data = await client.readContract({
            address: cdsAddress,
            abi: CDS_ABI,
            functionName: "getCDS",
            args: [BigInt(i)],
          }) as unknown as [string, string, bigint, bigint, bigint, number, boolean, string, string];

          results.push({
            id: i,
            buyer: data[0],
            seller: data[1],
            triggerPrice: data[2],
            maturityTimestamp: data[3],
            status: data[5],
            notionalDeposited: data[6],
            notionalHandle: data[7],
          });
        } catch {
          // skip invalid
        }
      }

      setContracts(results);
      setLoading(false);
    }

    loadContracts();
  }, [total, cdsAddress]);

  const myContracts = address
    ? contracts.filter(
        (c) =>
          c.buyer.toLowerCase() === address.toLowerCase() ||
          c.seller.toLowerCase() === address.toLowerCase()
      )
    : [];

  const activeCount = contracts.filter((c) => c.status === 0).length;
  const encryptedCount = contracts.filter((c) => c.notionalDeposited).length;

  return (
    <div className="min-h-screen bg-gray-950 text-white">
      {/* Hero */}
      <section className="px-6 py-16 max-w-6xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-6">
          <div>
            <div className="inline-flex items-center gap-2 text-xs font-mono text-cyan-400/80 bg-cyan-400/5 border border-cyan-400/20 rounded px-3 py-1 mb-5 tracking-widest uppercase">
              <span className="w-1.5 h-1.5 rounded-full bg-cyan-400 beacon" />
              Live · iExec Nox · Arbitrum Sepolia
            </div>
            <h1 className="text-4xl md:text-5xl font-bold tracking-tight mb-4 leading-tight">
              Hedge privately.<br />
              <span className="text-cyan-400">Settle trustlessly.</span>
            </h1>
            <p className="text-gray-400 text-base max-w-lg leading-relaxed">
              VEIL lets you protect your crypto position without revealing how much you&apos;re protecting.
              Your trade size stays encrypted on-chain — only you and your counterparty can see it.
            </p>
          </div>
          <div className="flex-shrink-0">
            <Link
              href="/create"
              className="btn-cyan inline-flex items-center gap-2 bg-cyan-400/10 hover:bg-cyan-400/15 border border-cyan-400/40 text-cyan-400 font-mono font-semibold px-6 py-3 rounded text-sm tracking-widest uppercase transition-all"
            >
              + New Position
            </Link>
          </div>
        </div>

        {/* Stats row */}
        <div className="mt-10 grid grid-cols-1 sm:grid-cols-3 gap-4">
          <div className="card-shimmer bracket-corner bg-[#080810] border border-[#0E1020] rounded p-4">
            <div className="text-[10px] text-cyan-400/50 mb-2 font-mono tracking-widest uppercase">Live ETH/USD</div>
            <PriceFeed compact />
          </div>
          <div className="card-shimmer bracket-corner bg-[#080810] border border-[#0E1020] rounded p-4">
            <div className="text-[10px] text-cyan-400/50 mb-2 font-mono tracking-widest uppercase">Active Contracts</div>
            <div className="text-2xl font-bold font-mono text-green-400">
              {loading ? <span className="animate-pulse text-gray-700">—</span> : activeCount}
            </div>
          </div>
          <div className="card-shimmer bracket-corner bg-[#080810] border border-[#0E1020] rounded p-4">
            <div className="text-[10px] text-cyan-400/50 mb-2 font-mono tracking-widest uppercase">Encrypted Notionals</div>
            <div className="text-2xl font-bold font-mono text-cyan-400">
              {loading ? <span className="animate-pulse text-gray-700">—</span> : encryptedCount}
            </div>
            <div className="text-[10px] text-gray-700 mt-1 font-mono">iExec Nox TEE</div>
          </div>
        </div>
      </section>

      {/* My Positions */}
      {address && (
        <section className="px-6 pb-10 max-w-6xl mx-auto">
          <div className="flex items-center gap-3 mb-4">
            <div className="h-px flex-1 bg-gradient-to-r from-cyan-400/20 to-transparent" />
            <span className="text-[10px] font-mono tracking-widest uppercase text-cyan-400/60">My Positions</span>
            <div className="h-px flex-1 bg-gradient-to-l from-cyan-400/20 to-transparent" />
          </div>
          {loading ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <SkeletonCard />
              <SkeletonCard />
            </div>
          ) : myContracts.length === 0 ? (
            <div className="bg-[#080810] border border-[#0E1020] rounded p-8 text-center text-gray-600 font-mono text-sm">
              No positions yet.{" "}
              <Link href="/create" className="text-cyan-400/70 hover:text-cyan-400 transition-colors">
                Open your first position →
              </Link>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {myContracts.map((c) => (
                <CDSCard key={c.id} {...c} cdsId={c.id} connectedAddress={address} />
              ))}
            </div>
          )}
        </section>
      )}

      {/* All Contracts */}
      <section className="px-6 pb-16 max-w-6xl mx-auto">
        <div className="flex items-center gap-3 mb-4">
          <div className="h-px flex-1 bg-gradient-to-r from-cyan-400/20 to-transparent" />
          <span className="text-[10px] font-mono tracking-widest uppercase text-cyan-400/60">All Positions</span>
          <div className="h-px flex-1 bg-gradient-to-l from-cyan-400/20 to-transparent" />
        </div>
        {loading ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <SkeletonCard />
            <SkeletonCard />
            <SkeletonCard />
          </div>
        ) : contracts.length === 0 ? (
          <div className="bg-[#080810] border border-[#0E1020] rounded p-10 text-center">
            <div className="font-mono text-4xl text-gray-800 mb-3">[ ]</div>
            <p className="text-gray-500 mb-4 text-sm">No positions on-chain yet.</p>
            <Link
              href="/create"
              className="btn-cyan inline-flex items-center gap-2 bg-cyan-400/10 hover:bg-cyan-400/15 border border-cyan-400/30 text-cyan-400 font-mono text-xs px-5 py-2.5 rounded uppercase tracking-widest transition-all"
            >
              Open First Position
            </Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {contracts.map((c) => (
              <CDSCard key={c.id} {...c} cdsId={c.id} connectedAddress={address} />
            ))}
          </div>
        )}
      </section>

      {/* How it works */}
      <section className="px-6 pb-20 max-w-6xl mx-auto">
        <div className="flex items-center gap-3 mb-8">
          <div className="h-px flex-1 bg-gradient-to-r from-cyan-400/20 to-transparent" />
          <span className="text-[10px] font-mono tracking-widest uppercase text-cyan-400/60">How It Works</span>
          <div className="h-px flex-1 bg-gradient-to-l from-cyan-400/20 to-transparent" />
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {[
            {
              step: "01",
              title: "Pick your protection",
              body: "Set an ETH price that scares you. If ETH drops below that, you get paid out. The amount you want protected is your notional.",
            },
            {
              step: "02",
              title: "Encrypt before sending",
              body: "Your notional amount is scrambled on your own device before it touches the blockchain. Nobody — not even us — can see the number.",
            },
            {
              step: "03",
              title: "Oracle watches 24/7",
              body: "Chainlink's price feed checks ETH/USD in real time. When your trigger is hit, the contract settles automatically. No one can stop it.",
            },
            {
              step: "04",
              title: "Private payout",
              body: "Only you and your counterparty can decrypt the payout size. On-chain, it's just an encrypted handle. Total privacy, zero trust required.",
            },
          ].map(({ step, title, body }) => (
            <div key={step} className="bracket-corner bg-[#080810] border border-[#0E1020] rounded p-5 hover:border-cyan-400/20 transition-colors">
              <div className="text-2xl font-black text-[#1A1B22] mb-3 font-mono">{step}</div>
              <h3 className="font-semibold text-gray-200 mb-2 text-sm">{title}</h3>
              <p className="text-xs text-gray-500 leading-relaxed">{body}</p>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}
